async (params, browser) => {
  // Search Walmart sorted by price
  await browser.open(`https://www.walmart.com/search?q=${params.query}&sort=price_low`)

  // Wait for results
  await browser.waitForSelector('[data-item-id], [class*=\'product-card\'], [class*=\'search-result\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Extract and compare prices
  const comparison_data = await browser.evaluate(`const items = []; const cards = document.querySelectorAll('[data-item-id], [class*="product-card"], [class*="search-result-gridview-item"]'); for (let i = 0; i < Math.min(cards.length, 20); i++) { const el = cards[i]; const titleEl = el.querySelector('[data-automation-id="product-title"], [class*="product-title"], [class*="title"] a'); const priceEl = el.querySelector('[data-automation-id="product-price"], [class*="price-main"], [class*="price"]'); const originalPriceEl = el.querySelector('[class*="was-price"], [class*="list-price"], s, del'); const ratingEl = el.querySelector('[class*="rating"] [class*="stars"]'); const reviewCountEl = el.querySelector('[class*="review-count"]'); const sellerEl = el.querySelector('[class*="seller"], [class*="fulfilled"]'); const linkEl = el.querySelector('a[href*="/ip/"]'); const shippingEl = el.querySelector('[class*="shipping"], [class*="delivery"]'); items.push({ title: titleEl ? titleEl.textContent.trim().substring(0, 200) : '', price: priceEl ? priceEl.textContent.trim() : '', original_price: originalPriceEl ? originalPriceEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', review_count: reviewCountEl ? reviewCountEl.textContent.trim() : '', seller: sellerEl ? sellerEl.textContent.trim() : '', shipping: shippingEl ? shippingEl.textContent.trim() : '', url: linkEl ? linkEl.href : '' }); } const prices = items.map(function(item) { return parseFloat(item.price.replace(/[^0-9.]/g, '')) || 0; }).filter(function(p) { return p > 0; }); const avgPrice = prices.length > 0 ? (prices.reduce(function(a, b) { return a + b; }, 0) / prices.length).toFixed(2) : '0'; return { query: params.query, item_count: items.length, price_summary: { average: '$' + avgPrice, lowest: prices.length > 0 ? '$' + Math.min.apply(null, prices).toFixed(2) : '$0', highest: prices.length > 0 ? '$' + Math.max.apply(null, prices).toFixed(2) : '$0' }, items: items }`)

  return comparison_data
}
